            if line == "ACT INLET OPEN":
                telemetry["saw_inlet_open"] = True
            elif line == "ACT INLET CLOSED":
                telemetry["saw_inlet_closed"] = True
            elif line == "ACT HEATER ON":
                telemetry["saw_heater_on"] = True
